#include<bits/stdc++.h>
using namespace std;

// Check if 'next' vertex can be added after vertex 'v'
bool check(int v, int next, vector<int> &circuit, vector<vector<bool>> &mat) {
    if(mat[v][next] == 0) // To check if v is adjacent to next
        return false;

    for(int i = 0; i < circuit.size(); i++) { // To check if next is already visited
        if(circuit[i] == next) 
            return false;
    }

    return true;
}

void backtrack(int v, int n, vector<int> &circuit, vector<vector<int>> &ans, vector<vector<bool>> &mat) {
    if(circuit.size() == n) { // Circuit is completed
        if(mat[circuit[0]][v] == 1) { // Check if cycle is completed, starting should be adjacent to ending
            circuit.push_back(circuit[0]);
            ans.push_back(circuit);
            circuit.pop_back();
        }
        return;
    }

    for(int i = 1; i <= n; i++) {
        // Calling the check function
        if(check(v, i, circuit, mat) == 0) 
            continue;

        // If not visit and is adjacent, add it to our candidate solution
        circuit.push_back(i);
        backtrack(i, n, circuit, ans, mat);
        circuit.pop_back();
    }
}   


// Number of vertices and adjacency matrix
vector<vector<int>> hamiltonian_circuit(int n, vector<vector<bool>> &mat) {
    vector<int> circuit; // Initially empty circuit
    vector<vector<int>> ans; // To store all the circuits

    for(int i = 1; i <= n; i++) { // Fix the starting vertex
        circuit.push_back(i); // Add i to circuit
        backtrack(i, n, circuit, ans, mat);
        circuit.pop_back(); // Remove i from circuit
    }

    return ans;
}

int main() {
    int n; cin >> n;
    int m; cin >> m;

    // Adjacency matrix
    vector<vector<bool>> mat(n + 1, vector<bool> (n + 1, false));
    while(m--) {
        int a, b;
        cin >> a >> b;
        mat[a][b] = 1;
        mat[b][a] = 1;
    }
    vector<vector<int>> cycles = hamiltonian_circuit(n, mat);
    sort(cycles.begin(), cycles.end());

    for(auto &x: cycles) {
        for(auto &y: x) {
            cout << y << " ";
        }
        cout << "\n";
    }
    return 0;
}

